import {{ Injectable }} from '@nestjs/common';
import {{ ExportService }} from './models/export.model';
import {{ ExportServiceRepository }} from './repositories/export.repository';

@Injectable()
export class ExportServiceService {{
  constructor(
    private readonly repository: ExportServiceRepository,
  ) {{}}

  async findAll(): Promise<ExportService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<ExportService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<ExportService>): Promise<ExportService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<ExportService>): Promise<ExportService> {{
    return this.repository.update(id, data);
  }}
}}
